Malware authors employ various techniques to detect and evade analysis environments, making reverse engineering more difficult.

**Debugger Detection:**

**Windows API-Based:**
```c
// IsDebuggerPresent
if (IsDebuggerPresent()) {
    ExitProcess(0);
}

// CheckRemoteDebuggerPresent
BOOL debugged = FALSE;
CheckRemoteDebuggerPresent(GetCurrentProcess(), &debugged);
if (debugged) ExitProcess(0);

// NtQueryInformationProcess
NTSTATUS status = NtQueryInformationProcess(
    GetCurrentProcess(), ProcessDebugPort, &debugPort, sizeof(debugPort), NULL);
if (debugPort != 0) ExitProcess(0);
```

**PEB (Process Environment Block):**
```c
// Check PEB.BeingDebugged flag directly
__asm {
    mov eax, fs:[0x30]  // PEB address
    movzx eax, byte ptr [eax+0x02]  // BeingDebugged
    test eax, eax
    jnz debugger_detected
}

// NtGlobalFlag check
// PEB.NtGlobalFlag == 0x70 when debugged
__asm {
    mov eax, fs:[0x30]
    mov eax, [eax+0x68]  // NtGlobalFlag
    cmp eax, 0x70
    je debugger_detected
}
```

**Timing-Based:**
```c
// RDTSC timing check
unsigned long long start = __rdtsc();
// ... some code ...
unsigned long long end = __rdtsc();
if (end - start > 100000) {
    // Debugger detected (single-stepping is slow)
    ExitProcess(0);
}

// GetTickCount
DWORD start = GetTickCount();
// ... code ...
if (GetTickCount() - start > 1000) ExitProcess(0);
```

**VM Detection:**
```c
// Check for VM artifacts
// Registry keys
RegOpenKeyEx(HKEY_LOCAL_MACHINE, "SOFTWARE\\VMware, Inc.\\VMware Tools", ...);
RegOpenKeyEx(HKEY_LOCAL_MACHINE, "SOFTWARE\\Oracle\\VirtualBox Guest Additions", ...);

// MAC address prefixes (VMware: 00:0C:29, VirtualBox: 08:00:27)
// Process names: vmtoolsd.exe, VBoxService.exe
// File checks: C:\Windows\System32\drivers\vmhgfs.sys

// CPUID check
__asm {
    mov eax, 1
    cpuid
    bt ecx, 31  // Hypervisor present bit
    jc vm_detected
}
```

**Sandbox Evasion:**
```c
// Check for human interaction
GetCursorPos(&pt1);
Sleep(5000);
GetCursorPos(&pt2);
if (pt1.x == pt2.x && pt1.y == pt2.y)
    ExitProcess(0);  // No mouse movement = sandbox

// File system checks (sandboxes have few files)
WIN32_FIND_DATA findData;
int fileCount = 0;
HANDLE hFind = FindFirstFile("C:\\Users\\*", &findData);
while (FindNextFile(hFind, &findData)) fileCount++;
if (fileCount < 10) ExitProcess(0);  // Too few files

// Uptime check (sandboxes just booted)
